













import Vue from 'vue';
import {createComponent, reactive, ref, onMounted, computed, SetupContext} from "@vue/composition-api";

export default createComponent({
    setup(props, { root }: SetupContext) {
        let store = root.$store;
        const title = ref('CCORK');

        const modal_open = (kind: string) => {
            store.commit('modal_open', {kind});
        }

        const open_upload = () => {
            store.commit('open_upload');
        }

        onMounted(() => {
        })

        const bar_animation = computed(() => {return {
                'bar-animation': store.getters.is_loading,
        }})

        return {title, bar_animation, modal_open, open_upload}
    }
});
