import Vue from 'vue';
import Component, { mixins } from 'vue-class-component';
import {AbstractStorage, ImgWithPosition, Board} from './storage/header';
import {Mixins} from 'vue-property-decorator';
import img_position  from './img_position';

@Component
export default class BoardComponent extends Mixins(img_position) {

    zoom_rate = 0.5
    zoom_step = 0
    initial_zoom_rate = 0.5 //zoom_rateの初期値
    initial_zoom_step = 0

    // ts suppression
    imgs_index: Map<string, ImgWithPosition>
    storage: AbstractStorage
    view_img_ids: string[]
    board: Board
    $refs: any
    previous_scroll: number[] = null

    /**ズーム処理 */
    zoom(e) {
        // ホイールの加速方向から変化率を選択
        const accel =  (e.deltaY < 0) ?  1 : -1;
        const zoom_step = this.zoom_step + accel

        // 次のフレームのzoom倍率を計算
        let next_zoom = this.initial_zoom_rate　// 0の時のズーム率
        if(this.zoom_step<0) {
            next_zoom *= 0.9 ** Math.abs(zoom_step);
        }else if(this.zoom_step>0) {
            next_zoom *= 1.1 ** Math.abs(zoom_step);
        }
        console.log()

        // 縮小方向でウィンドウよりも大きくならないようにする
        const cond1 = accel > 0 || this.board.width * next_zoom > this.$refs.frame.offsetWidth;
        const cond2 = accel > 0 || this.board.height * next_zoom > this.$refs.frame.offsetHeight;
        if(cond1 && cond2) { // フレーム以下のサイズ
            /**
             * ズーム後もマウスが指している位置が変わらないようにズームする
             * 現在のスクロール位置 + 次のズームで発生する差分
             */

            // マウスの発火位置
            const abs_pos = this.get_offset(e).map(n => n * this.zoom_rate);
            const rel_pos = [e.x, e.y];
            // 可視領域での発火位置
            const zoom_offset = next_zoom - this.zoom_rate;

            let scrolls = []
            for(let i = 0; i < 2; i++) {
                const norm_abs_mouse = abs_pos[i] / this.zoom_rate;
                const add_offset = norm_abs_mouse * zoom_offset;
                const now_scroll_top = abs_pos[i] - rel_pos[i]; // 全体のマウス座標 - 画面のマウス座標
                const scroll = now_scroll_top + add_offset;

                // 飛ぶバグ対策(原因不明)
                if(this.previous_scroll != null) {
                    if(Math.abs(scroll / next_zoom - this.previous_scroll[i]) > 5000) {
                        this.previous_scroll = null;
                        return;
                    }
                }
                scrolls.push(scroll)
            }

            this.zoom_step = zoom_step;
            console.log('next_zoom:', next_zoom)
            this.zoom_rate = next_zoom;
            this.$store.commit('zoom_change', {
                'zoom_rate': next_zoom,
                'zoom_step': this.zoom_step
            });

            this.$nextTick(function() {
                this.$refs.frame.scrollTo(scrolls[0], scrolls[1]);
                this.previous_scroll = scrolls.map(x => x / this.zoom_rate);
            });
        }

    }

    /** zoom_rateに一番近いstepを探す
     * TODO: +-20stepくらい事前計算してfilterしたほうが高速かつ安全かも
    */
    search_zoom_step(zoom_rate: number) {
        if(zoom_rate < 1) {
            let count = 0;
            while(true) {
                const z = this.initial_zoom_rate * (0.9 ** count)
                if(z < zoom_rate) {
                    break
                }
                count++;
            }
            return -count
        } else {
            let count = 0;
            while(true) {
                const z = this.initial_zoom_rate * (1.1 ** count)
                if(z > zoom_rate) {
                    break
                }
                count++;
            }
            return count;
        }
    }

    /**ダブルクリックされたとき */
    pickup_img(img: ImgWithPosition) {
        let zoom_rate = 0;
        const client_width = this.$refs.frame.clientWidth;
        const client_height = this.$refs.frame.clientHeight;
        if(img.pos.fixed_height > img.pos.fixed_width){
            zoom_rate = client_height / img.pos.fixed_height;
        } else {
            zoom_rate = client_width / img.pos.fixed_width;
        }
        this.zoom_step = this.search_zoom_step(zoom_rate);
        this.zoom_rate = zoom_rate;
        const scroll_x = img.pos.x * zoom_rate - client_width / 2;
        const scroll_y = img.pos.y * zoom_rate - client_height / 2;
        this.$nextTick(function() {
            this.$refs.frame.scrollTo(scroll_x, scroll_y);
            this.previous_scroll = null;
        });


        this.$store.commit('zoom_change', zoom_rate);
        this.replace_reduce_blob();
    }

}
