import Vuex from 'vuex';
import Vue from 'vue';
import createPersistedState from "vuex-persistedstate";
import {Board, Theme} from './board/storage/header';

Vue.use(Vuex);


const session = {
    state: {
        zoom_rate: 0.5,
        zoom_step: 1,
        saving_view: false,
        lock: false, // 編集ロックモード
    },
    mutations: {
        zoom_change: function(state, payload) {
            state.zoom_rate = payload['zoom_rate'];
            state.zoom_step = payload['zoom_step'];
        },
        change_view_saving: function(state, payload) {
            state.view_saving = payload;
        },
        change_lock: function(state, payload) {
            state.lock = payload;
        },
    },
    actions: {},
}

export default new Vuex.Store({
    plugins: [createPersistedState({
        key: 'corkboard',
        paths: ['session']
    })],
    state: {
        //zoom_rate: 0,
        loading: 0,
        board: 'local',
        board_modal: null,
        debug: true, // デバックモード
        upload: false, // openコンポーネントの起動
    },
    getters: {
        is_loading: function(state) {
            return state.loading > 0;
        },
    },
    modules: {
        session,
    },
    actions: {},
    mutations: {

        start_loading: function(state) {
            state.loading += 1;
        },
        end_loading: function(state){
            if(state.loading > 0) {
                state.loading -= 1;
            }
        },
        modal_close: function(state) {
            state.board_modal = null;
        },
        modal_open: function(state, payload) {
            if(payload.kind == state.board_modal){
                // 同じモーダルの表示要求が来たら閉じる
                state.board_modal = null;
                return;
            }
            state.board_modal = payload.kind;
        },
        change_debug: function(state, payload) {
            state.debug = payload;
        },
        close_upload: function(state) {
            state.upload = false;
        },
        open_upload: function(state) {
            state.upload = true;
        },
    }
})