































import Vue from 'vue';
import {createComponent, watch, computed,reactive, ref, onMounted, SetupContext, Ref} from "@vue/composition-api";
import {board_manager_factory} from '../storage';
import {AbstractBoardManager, Board, Theme} from '../storage/header';
import ModalClose from './chips/modal-close-button.vue';
import ThemeButton from './chips/theme-button.vue';

type Props = {
    backgroundtheme: String,
    backuping: boolean,
};


export default createComponent({
    components: {
        'modal-close': ModalClose,
        'theme-button': ThemeButton
    },
    props: {
        backgroundtheme: {
            type: String,
        },
        backuping: {
            type: Boolean
        }
    },
    setup(props: Props, ctx: SetupContext) {
        const store = ctx.parent.$store;
        const route = ctx.parent.$route;
        const router = ctx.parent.$router;
        const emit = ctx.emit
        const bm = board_manager_factory();
        let now_board = ref({'path': ''} as Board);

        const close_model = () => {
            store.commit('modal_close');
        }

        onMounted(async () => {
            const path = route.params.board_path;
            const tmp = await bm.get_board(path);
            now_board.value = tmp;
        })

        const name_span: Ref<HTMLElement> = ref(null)
        const change_board_name = (e) => {
            name_span.value.blur();
            now_board.value.name = name_span.value.textContent;
            bm.update_board(now_board.value);
        }

        const toggle_debug_mode = () => {
            store.commit('change_debug', !store.state.debug);
        }

        const toggle_lock_mode = () => {
            store.commit('change_lock', !store.state.lock);
        }

        const view_reset = () => {
            emit('view-reset');
        }

        let delete_count = 0
        const delete_msg = ref('DELETE BOARD')
        const delete_board = () => {
            if(delete_count <= 1) {
                delete_msg.value = 'OK' + '?'.repeat(delete_count+1);
                delete_count++;
                setTimeout(() => {
                    delete_msg.value = 'DELETE'
                    delete_count = 0
                }, 5000)
                return;
            }
            bm.delete_board(now_board.value.path);
            store.commit('modal_close');
            router.push('/');

        }

        const change_theme = (theme) => {
            emit('change-theme', theme);
        }

        const backup = () => {
            emit('backup')
        }

        const backup_msg = computed(() => {
            if(props.backuping) {
                return 'IN PROGRESS';
            }
            return 'BACKUP';
        })

        const theme = props.backgroundtheme;
        return {props, backup_msg, backup, change_theme, theme, view_reset, delete_msg, delete_board, close_model, now_board, toggle_lock_mode, change_board_name, name_span, store, toggle_debug_mode}
    }
});

