import {Img, Position, AbstractStorage, ImgWithPosition, Board, AbstractBoardManager, Theme} from '../storage/header';
import {storage_factory, board_manager_factory} from '../storage';
import * as zip from "jsziptools/zip";
import * as common from "jsziptools/common";
import { generate_uuid } from '../storage/uuid';

export default class Serialize {

    board_manager: AbstractBoardManager
    storage: AbstractStorage

    constructor(){
        this.board_manager = board_manager_factory();
    }


    /**
     * ImgWithPositionをobjctに変換する（blobをフィルタ）
     * TODO: もっといいclass to object変換方法
     */
    iwp_to_obj(iwp: ImgWithPosition) {
        return {
            'id': iwp.id,
            'img': {
                'filename': iwp.img.filename,
                'width': iwp.img.width,
                'height': iwp.img.height,
            },
            'pos': {
                'x': iwp.pos.x,
                'y': iwp.pos.y,
                'fixed_width': iwp.pos.fixed_width,
                'fixed_height': iwp.pos.fixed_height,
            }
        }
    }

    /**
     * zipからボードを復元する
     * TODO: 無圧縮のzipじゃないとうまく行かない
    */
    async recovery(file: Blob) {
        console.log('file:', file)
        const buffer = await file.arrayBuffer()
        const reader = await zip.unpack({
            'buffer': buffer,
            'encoding': 'UTF-8',
        });

        const raw_str = await reader.readFileAsText('metadatas.json');
        const raw_str2 = await reader.readFileAsText('board_metadata.json');
        const metadatas: any[] = JSON.parse(raw_str);
        const bmetadatas: [] = JSON.parse(raw_str2);

        const path = generate_uuid();
        const board = new Board(path,
                  bmetadatas['name'] + '_recovery',
                  bmetadatas['width'],
                  bmetadatas['height'],
                  bmetadatas['theme'])
        this.board_manager.insert_board(board)
        const storage = storage_factory(board);

        let p = [];
        for(let m of metadatas) {
            const simg = m['img'];
            const serialize_filename = simg['serialize_filename'];
            const blob = await reader.readFileAsBlob(`imgs/${serialize_filename}`);
            const img = new Img(simg['width'], simg['height'], simg['filename'], blob);

            const spos = m['pos'];
            const pos = new Position(spos['x'],
                                     spos['y'],
                                     spos['fixed_width'],
                                     spos['fixed_height']);
            const iwp = new ImgWithPosition(m['id'], img, pos);

            p.push(storage.insert(iwp));
        }
        Promise.all(p);
    }

    /**
     * javascriptでzip圧縮を行う処理
     * 重いのでworkerに委譲している
     */
    async serialize(board_path: string) {
        const board = await this.board_manager.get_board(board_path);
        const storage = storage_factory(board);

        const worker = new Worker('./serialize.worker.ts');
        const ext_table = {
            'image/jpeg': 'jpg',
            'image/png': 'png',
            'image/bmp': 'bmp',
            'image/gif': 'gif',
        }

        const metadatas = []
        for(let img_id of await storage.get_ids()) {
            const iwp = await storage.get(img_id);

            const t = iwp.img.blob.type;
            const ext = ext_table[t];
            const fname = `${iwp.id}.${ext}`;

            const metadata = this.iwp_to_obj(iwp)
            metadata['img']['serialize_filename'] = fname
            metadatas.push(metadata);

            const buffer = await common.readFileAsArrayBuffer(iwp.img.blob);
            const file = {
                'name': fname,
                'buffer': buffer,
            }
            worker.postMessage(file, [file.buffer]);  // bufferは参照渡し
        }
        worker.postMessage('add_files_end');
        worker.postMessage(metadatas);
        worker.postMessage(board);
        worker.postMessage('start_compress');

        const buffer: Uint8Array = await new Promise(resolve => {
            worker.addEventListener('message', (e) => {
                resolve(e.data);
            }, false);
        });
        return new Blob([buffer], {type: 'application/zip'});
    }
}