import Vue from 'vue';
import Component from 'vue-class-component';
import {Img, Position, AbstractStorage, ImgWithPosition, Board, AbstractBoardManager} from './storage/header';
import {generate_uuid} from './storage/uuid';

@Component
export default class BoardComponent extends Vue {

    upload_max_px = 2000

    // ts suppression
    storage: AbstractStorage
    zoom_rate: number
    imgs: ImgWithPosition[]
    view_img_ids: string[]
    $refs: any

    async get_img_size(img_blob): Promise<{width: number, height: number}>{
        const img = new Image();
        img.src = window.URL.createObjectURL(img_blob);

        return new Promise(resolve => {
            const fire = () => {
                let width = img.width;
                let height = img.height;
                resolve({width, height});
                img.removeEventListener('load', fire, false);
            };
            img.addEventListener('load', fire, false);
        });
    }


    fix_size(width, height): {width: number, height: number} {
        /** 画像のサイズが大きすぎる場合は制限をかける */
        if(width > this.upload_max_px || height > this.upload_max_px) {
            if(width > height) {
                var new_width = this.upload_max_px;
                const grow_rate = new_width / width;
                var new_height = height * grow_rate;
            } else {
                var new_height = this.upload_max_px;
                const grow_rate = new_height / height;
                var new_width = width * grow_rate;
            }
            width=Math.round(new_width);
            height = Math.round(new_height);
        }
        return {width, height}
    }

    async upload_image_without_position(files) {
        /** 座標がないアップロード
         * 画面の中央あたりに配置する
        */
        // ちょっと揺らがせる
        const rand = () => Math.random() * 500 - 250
        const frame_width = this.$refs.frame.clientWidth / this.zoom_rate + rand();
        const frame_height = this.$refs.frame.clientHeight / this.zoom_rate + rand();
        const frame_top = this.$refs.frame.scrollTop / this.zoom_rate + rand();
        const frame_left = this.$refs.frame.scrollLeft / this.zoom_rate + rand();

        this.upload_image(
            frame_left + frame_width / 2,
            frame_top + frame_height / 2,
            files)
    }

    async upload_image(x, y, files) {
        /**
         * イメージのアップロード
         */
        console.log("upload image.");

        if (!files.length) {
            console.log("No files!");
            return;
        }

        for (var i = 0; i < files.length; i++) {
            const size = await this.get_img_size(files[i]);
            const {width, height} = this.fix_size(size.width, size.height);
            const id = generate_uuid();

            const fixed_x = x + 500 * i; //複数張り付けた時に横にずらす
            const pos = new Position(fixed_x, y, width, height);
            const imgo = new Img(size.width, size.height, files[i].name, files[i]);
            const iwp = new ImgWithPosition(id, imgo, pos);

            await this.storage.insert(iwp);

            // アップロードしたイメージを再取得
            // TODO: 圧縮済みイメージのロードが間に合わない
            const img = await this.storage.get(id, this.zoom_rate);
            this.imgs.push(img);

            this.view_img_ids.push(img.id);
        }
    }

    delete_img(img) {
        this.storage.delete(img.id);

        const i = this.imgs.indexOf(img);
        this.imgs.splice(i, 1);
    }

}
