import Vue from 'vue';
import Component from 'vue-class-component';
import {AbstractStorage, ImgWithPosition, Board} from './storage/header';
import Serialize from './serialize'
import * as common from "jsziptools/common";

@Component
export default class BoardComponent extends Vue {

    storage: AbstractStorage = null
    serializing: boolean = false

    // supression
    $route: any
    board: Board

    async download() {
        this.serializing = true;
        try {
            const s = new Serialize()
            const blob = await s.serialize(this.board.path);
            const a = document.createElement("a");
            a.download = `${this.board.path}.zip`
            a.href = URL.createObjectURL(blob);
            a.click();
        } finally {
            this.serializing = false;
        }

    }
}
