import {AbstractStorage, AbstractBoardManager, Img, Position, Compress, ImgWithPosition, Board} from './header';


/**
 * 画像の圧縮（縮小）を行う処理
 */
export default class Compressor {
    canvas: HTMLCanvasElement
    ctx: CanvasRenderingContext2D

    constructor() {
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
    }

    async compress(iwp: ImgWithPosition, reduce_deno: number): Promise<Blob>{
        /**
         * TODO: ImgWithPositionの依存を除去したい
         */
        const img = await this._load_img(iwp)

        this.canvas.width=img.width / reduce_deno;
        this.canvas.height=img.height / reduce_deno;

        const rate = 1 / reduce_deno;
        this.ctx.scale(rate, rate);
        this.ctx.drawImage(img, 0, 0);
        return this._canvas_toblob();
    }

    async _canvas_toblob(): Promise<Blob> {
        /** キャンバスをblobに変換する */
        return new Promise(resolve => {
            const load = (blob) => resolve(blob);
            this.canvas.toBlob(load, 'image/jpeg');
        });
    }

    async _load_img(iwp: ImgWithPosition): Promise<HTMLImageElement> {
        const img = new Image();
        img.src = URL.createObjectURL(iwp.img.blob);
        // イメージのロードを待つ
        await new Promise(resolve => img.addEventListener('load', () => {resolve()}, false));
        return img;
    }

    calc_reduce_deno(width: number, fixed_width: number, zoom_rate: number) {
        /** 減少率の分母の計算 (denomition) */
        const img_deno = 1 / (fixed_width / width);
        return img_deno * 1 / zoom_rate;
    }
}