

























import {ImgWithPosition} from './storage/header';
import { Component, Prop, Vue } from 'vue-property-decorator';

@Component({
  props: {
    img: ImgWithPosition,
    active: Boolean,
  }
})
export default class PinImg extends Vue {

    img: ImgWithPosition
    num_click = 0
    resize = false

    get src() {
        return window.URL.createObjectURL(this.img.img.blob);
    }

    get styles() {
        return {
            'top': (this.img.pos.y - this.img.pos.fixed_height / 2) + "px",
            'left': (this.img.pos.x - this.img.pos.fixed_width / 2) + "px",
            'width': this.img.pos.fixed_width,
            'height': this.img.pos.fixed_height,
        }
    }

    get info_msg() {
        if(this.$store.state.debug){
            return [
                `id: ${this.img.id}`,
                `filename: ${this.img.img.filename}`,
                `x: ${this.img.pos.x}`,
                `y: ${this.img.pos.y}`,
                `fixed_width: ${this.img.pos.fixed_width}`,
                `fixed_height: ${this.img.pos.fixed_height}`,
                `width: ${this.img.img.width}`,
                `height: ${this.img.img.height}`,
                `reduce_deno: ${this.img.reduce_deno}`,
            ].join('\n');
        }
        return '';
    }

    get_size_rate() {
        const rate1 = this.img.pos.fixed_width / this.img.img.width;
        const rate2 = this.$store.state.zoom_rate;
        return rate1 * rate2;
    }

    async sleep(msec) {
        return new Promise(resolve => setTimeout(resolve, msec))
    }

    pickup() {
        console.log("doubleclick");
        this.$emit('pickup');
    }

    select_img_event = null
    async mouse_down(e) {
        /**
         * 画像のセレクトの判定と
         */

        // doubleclick
        this.num_click++;

        // ダブルクリック時にselect_img送信を防ぐ
        if(this.select_img_event==null) {
            this.select_img_event = setTimeout(()=>{
            if(this.num_click <= 1){
                    this.$emit('select_img', e);
                    this.select_img_event = null;
                }
            }, 200)
        }

        if(this.num_click>=2) {
            this.pickup();
            this.num_click=0;
        }else{
            let _ = await this.sleep(300);  // 0.3s
            if(this.num_click>0) {
                this.num_click--;
            }
        }
    }

    mouse_up(e) {
        this.$emit('relase_img', e);
        this.end_resize();
    }

    begin_resize() {
        this.$emit('begin_resize');
    }

    end_resize() {
        this.$emit('end_resize');
    }

    delete_img() {
        if(this.$store.state.lock){return}
        this.$emit('delete_img');
    }
}
