import Vue from 'vue';
import Component, { mixins } from 'vue-class-component';

import { AbstractStorage, ImgWithPosition } from './storage/header';
import {Watch, Mixins} from 'vue-property-decorator';
import img_position  from './img_position';

@Component
export default class BoardComponent extends Mixins(img_position) {

    resize_img: ImgWithPosition = null
    zoom_rate: number
    storage: AbstractStorage

    begin_resize(img) {
        if(this.$store.state.lock){return}
        console.log('resize:', img.id);
        this.resize_img = img;
    }

    end_resize() {
        if(this.resize_img){
            console.log('end resize');
            // 小数点以下を補正
            this.$set(this.resize_img.pos, 'fixed_width', Math.round(this.resize_img.pos.fixed_width));
            this.$set(this.resize_img.pos, 'fixed_height', Math.round(this.resize_img.pos.fixed_height));
            this.$set(this.resize_img.pos, 'x',  Math.round(this.resize_img.pos.x));
            this.$set(this.resize_img.pos, 'y',  Math.round(this.resize_img.pos.y));

            // dbに登録
            let img = this.resize_img;
            this.storage.update(img.id, img.pos);
            this.resize_img = null;
        }
    }

    _mousemove_for_resize(e) {
        /**
         * resize処理
         * センターを中心にするやつ
         */
        if(this.resize_img) {
            let [x, y] = this.get_offset(e);

            let new_width = Math.abs(x - this.resize_img.pos.x) * 2;
            let grow_rate = new_width / this.resize_img.pos.fixed_width;
            let new_height = this.resize_img.pos.fixed_height * grow_rate;
            this.$set(this.resize_img.pos, 'fixed_width', new_width);
            this.$set(this.resize_img.pos, 'fixed_height', new_height);
        }
    }

    mousemove_for_resize(e) {
        /**
         *  resize処理
         * 右上を中心にするやつ
         */
        if(this.resize_img) {
            const [mouse_x, mouse_y] = this.get_offset(e);

            const top = this.resize_img.pos.y - this.resize_img.pos.fixed_height / 2
            const left = this.resize_img.pos.x - this.resize_img.pos.fixed_width / 2

            const new_width = mouse_x - left;
            if(new_width > 100) {
                // これ以上は小さくしない
                const grow_rate = new_width / this.resize_img.img.width;
                const new_height = this.resize_img.img.height * grow_rate;

                const offset_x = (new_width - this.resize_img.pos.fixed_width) / 2;
                const offset_y = (new_height - this.resize_img.pos.fixed_height) / 2;
                const new_x = this.resize_img.pos.x + offset_x;
                const new_y = this.resize_img.pos.y + offset_y;

                this.$set(this.resize_img.pos, 'fixed_width', new_width);
                this.$set(this.resize_img.pos, 'fixed_height', new_height);
                this.$set(this.resize_img.pos, 'x', new_x);
                this.$set(this.resize_img.pos, 'y', new_y);
            }
        }
    }

}
