
import Vue from 'vue';
import {createElement, createComponent, reactive, ref, onMounted, SetupContext} from "@vue/composition-api";
import { Theme } from '../../storage/header';

type Props = {
    theme: String
};


export default createComponent({
    props: {
        theme: {
            type: String,
        }
    },
    setup(props, {parent, emit}: SetupContext) {
        const store = parent.$store;

        const change_theme = (value) => {
            emit('change-theme', value);
            store.commit('modal_close');
        }

        return () => {
            const child = [];

            const title = createElement('div', 'THEME');
            child.push(title);

            const classes = ['modal_button', 'modal_number-button', 'inline'];
            let count = 1;
            Object.entries(Theme).forEach(([key, value]) => {
                const mclasses = value == props.theme ? classes.concat(['modal_button_enable']): classes;
                const on = {
                    click: () => change_theme(value)
                }

                const node = createElement('div', {'class': mclasses, 'on': on}, count.toString());
                child.push(node);
                count += 1;
            })

            const div = createElement('div', {'class': 'buttons'}, child);
            return div;
        }
    }
})
