






import {createComponent, reactive, ref, onMounted, SetupContext} from "@vue/composition-api";
import {Img, Position, AbstractStorage, ImgWithPosition, Board, AbstractBoardManager} from './board/storage/header';
import {storage_factory, board_manager_factory} from './board/storage';
import { generate_uuid } from "./board/storage/uuid";

/**
 * 選択ボードがないとき用のリダイレクトコンポーネント
 */
export default createComponent({

    setup(props, { parent }: SetupContext){
        const router = parent.$router;

        const created = async () => {
            const bm = board_manager_factory();
            const boards = await bm.get_boards();
            if(boards.length <= 0) { // ボードが無かった
                const path = generate_uuid();
                // ボード新規作成
                router.push({name: 'board', params:{board_path: path}});
                return;
            }

            const board = boards[0];
            router.push({name: 'board', params:{board_path: board.path}});
        }
        created();
        return {};
    }
})
